/// <summary>
/// The <c>ETGSalesRegisterReportDP</c> class is the report data provider class for Sales register report
/// </summary>
[
    SRSReportQueryAttribute(queryStr(ETGSalesRegisterReportQuery)),
    SRSReportParameterAttribute(classStr(ETGSalesRegisterReportContract))
]
class ETGSalesRegisterReportDP extends SrsReportDataProviderPreProcessTempDB
{
    ETGSalesRegisterReportTmp       salesRegisterReportTmp;
    ETGSRSReportMultiParametersTmp  ssrsReportMultiParametersTmp;
    CreatedTransactionId            currentTransactionId, currentTransactionIdChrg, currentTransactionIdGRN;
    CustPackingSlipJour             custPackingSlipJour;
    CustPackingSlipTrans            custPackingSlipTrans;
    ETGSalesRegisterReportContract  contract;
    FromDate                        fromDate;
    ToDate                          toDate;
    DimensionSetName                financialDimSet;
    NoYes                           isDetailReport;
    EcoResConfigurationFlag         viewConfigId;
    EcoResSizeFlag                  viewInventSizeId;
    EcoResColorFlag                 viewInventColorId;
    EcoResStyleFlag                 viewInventStyleId;
    InventSiteIdFlag                viewInventSiteId;
    InventLocationIdFlag            viewInventLocationId;
    WHSLicensePlateFlag             viewLicensePlate;
    InventLocationIdFlag            viewWMSLocationId;
    WHSInventStatusFlag             viewInventStatus;
    InventBatchIdFlag               viewInventBatchId;
    InventSerialIdFlag              viewInventSerialId;
    InventOwnerIdFlag               viewInventOwnerId;
    utcDateTime                     utcFromDate, utcToDate;
    SalesId                         currentSalesId;
    RefRecId                        currentSalesLine;

    SalesTable                      salesTable;
    SalesLine                       salesLine;
    InventDim                       inventDim;

}

Method.Source:
[SRSReportDataSetAttribute(tablestr(ETGSalesRegisterReportTmp))]
public ETGSalesRegisterReportTmp getETGSalesRegisterReportTmp()
{
    select salesRegisterReportTmp;
    return salesRegisterReportTmp;
}

/// <summary>
///    Parses the report parameters and fills the <c>ETGSalesRegisterReportTmp</c> and <c>ETGSalesRegisterReportTmp</c>
///    tables with data.
/// </summary>
public void processReport()
{
    this.initContract();
    this.insertData();
    this.updateData();
    this.insertFinancialDimensions();
    this.insertChargeCodes();
}

/// <summary>
///    Parses the report parameters and fills the <c>ETGSalesRegisterReportTmp</c> and <c>ETGSalesRegisterReportTmp</c>
///    tables with data.
/// </summary>
public void initContract()
{
    contract                = this.parmDataContract() as ETGSalesRegisterReportContract;
    fromDate                = contract.parmFromDate();
    toDate                  = contract.parmToDate();
    financialDimSet         = contract.parmFinancialDimSet();
    isDetailReport          = contract.parmIsDetailReport();
    viewConfigId            = contract.parmViewConfigId();
    viewInventSizeId        = contract.parmViewInventSizeId();
    viewInventColorId       = contract.parmViewInventColorId();
    viewInventStyleId       = contract.parmViewInventStyleId();
    viewInventSiteId        = contract.parmViewInventSiteId();
    viewInventLocationId    = contract.parmViewInventLocationId();
    viewLicensePlate        = contract.parmViewWMSLocationId();
    viewWMSLocationId       = contract.parmViewWMSLocationId();
    viewInventStatus        = contract.parmViewInventStatus();
    viewInventBatchId       = contract.parmViewInventBatchId();
    viewInventSerialId      = contract.parmViewInventSerialId();
    viewInventOwnerId       = contract.parmViewInventOwnerId_RU();
}

/// <summary>
///    inserting data useing parm query
/// </summary>
public void insertData()
{
    QueryRun                        queryRun;
    FiscalCalendarYear              fiscalCalendarYear;
    CustTable                       custAccountTable;
    ETG_SalesTableTrade             salesTableTrade;
    ETG_OrderType                   etg_orderType;
    SalesAgreementHeader            salesAgreementHeader;
    AgreementReference              agreementReference;
    AgreementHeader                 agreementHeader;
    AgreementLine                   agreementLine;
    AgreementLineQuantityCommitment aLineCommitment;
    PurchAgreementHeader            purchAgreeementHeader;
    ETG_SalesAgreementHeader        etg_salesagreementheader;
    CustInvoiceJour                 custInvoiceJour;
    CustInvoiceTrans                custInvoiceTrans;
    CustTrans                       custTrans;
    TaxTrans                        taxTrans;
    GeneralJournalAccountEntry      generalJournalAccountEntry;
    GeneralJournalEntry             generalJournalEntry;
    AgreementLineQuantityCommitment agreementLineQuantityCommitment;
    InventTransOrigin               inventTransOriginMarked;
    InventTrans                     inventTransMarking;
    real                            invoiceQty, invoiceValue, taxAmountInv, invoiceAmount, cogsDiffered, cogsActual;
    real                            AmountCur, ReportingCurrencyAmount, AmountMST;
    Description255                  markedPurchIds;
    Query                           query = this.parmQuery();
    Ledger                          ledger = Ledger::find(Ledger::current());
    InventTransOrigin               inventTransOrigin;
    InventTrans                     inventTrans;
    ETG_AgreementType               AgreementType;

    //Start    sales register s3 date 28/03/2022
    InventTrans                     inventTransAdj;
    InventTransOrigin               inventTransOriginAdj;
    //End     sales register s3 date 28/03/2022

    utcFromDate = DateTimeUtil::newDateTime(fromDate, 0);
    utcToDate   = DateTimeUtil::newDateTime(toDate, 86400);
    query.dataSourceTable(tablenum(SalesTable)).addRange(fieldnum(SalesTable, CreatedDateTime)).value(queryRange(utcFromDate, utcToDate));

    queryRun = new QueryRun(query);
    while (queryRun.next())
    {
        salesTable                  = queryRun.get(tableNum(SalesTable));
        salesLine                   = queryRun.get(tableNum(SalesLine));
        inventDim                   = queryRun.get(tableNum(InventDim));
        custPackingSlipJour         = queryRun.get(tableNum(CustPackingSlipJour));
        custPackingSlipTrans        = queryRun.get(tableNum(CustPackingSlipTrans));
        custInvoiceJour             = queryRun.get(tableNum(CustInvoiceJour));
        custInvoiceTrans            = queryRun.get(tableNum(CustInvoiceTrans));

        salesRegisterReportTmp.clear();
        markedPurchIds      = "";
        if (currentSalesId != salesLine.SalesId || currentSalesLine != salesLine.RecId)
        {
            currentSalesId      = salesLine.SalesId;
            currentSalesLine    = salesLine.RecId;
            salesRegisterReportTmp.IsFirstLineInOrder   = NoYes::Yes;
        }
        else
        {
            salesRegisterReportTmp.IsFirstLineInOrder   = NoYes::No;
        }

        salesRegisterReportTmp.SalesTable           = salesTable.RecId;
        salesRegisterReportTmp.SalesLine            = salesLine.RecId;
        salesRegisterReportTmp.InventDim            = inventDim.RecId;
        salesRegisterReportTmp.SalesId              = salesTable.SalesId;
        salesRegisterReportTmp.InventTransId        = salesLine.InventTransId;
        salesRegisterReportTmp.IsActualOrderLine    = NoYes::Yes;
        salesRegisterReportTmp.CreatedDate          = DateTimeUtil::date(salesTable.CreatedDateTime);
        salesRegisterReportTmp.GLAccoutingCurrencyCode  = ledger.AccountingCurrency;
        salesRegisterReportTmp.GLReportingCurrencyCode  = ledger.ReportingCurrency;

        if (salesRegisterReportTmp.IsFirstLineInOrder && isDetailReport && salesLine.DefaultDimension)
        {
            salesRegisterReportTmp.DefaultDimension = salesLine.DefaultDimension;
        }
        else if (salesTable.DefaultDimension)
        {
            salesRegisterReportTmp.DefaultDimension = salesTable.DefaultDimension;
        }
        salesRegisterReportTmp.PaymTermId           = salesTable.DlvTerm;
        salesRegisterReportTmp.CurrencyCode         = salesTable.CurrencyCode;

        select firstonly salesTableTrade
            where salesTableTrade.SalesId == salesTable.SalesId;
        //if (salesTableTrade.FromDatePort && salesTableTrade.ToDatePort)
        {
            salesRegisterReportTmp.ShipmentPeriod       = strFmt("%1 %2", salesTableTrade.FromDatePort, salesTableTrade.ToDatePort);
        }
        salesRegisterReportTmp.ShipToPartyCode      = salesTableTrade.ShipperBuyer;
        //salesRegisterReportTmp.ShipToPartyName      = salesTableTrade.Name;
        //salesRegisterReportTmp.ShipToPartyName      = CustTable::find(salesTableTrade.ShipperBuyer).name();
        salesRegisterReportTmp.ShipToPartyName      = VendTable::find(salesTableTrade.ShipperBuyer).name();
        salesRegisterReportTmp.WeighbridgeNum       = salesTableTrade.WeighbridgeNum;
        salesRegisterReportTmp.GrossWeight          = salesTableTrade.GrossWeight;
        salesRegisterReportTmp.NetWeight            = salesTableTrade.NetWeight;
        salesRegisterReportTmp.TransporterName      = salesTableTrade.TransporterName;
        //salesRegisterReportTmp.GrossContribution    = salesTableTrade.GrossContribution;
        salesRegisterReportTmp.PaymTermDesc         = salesTableTrade.TermsOfDelDescription;
        salesRegisterReportTmp.SoldToCountry        = LogisticsAddressCountryRegionTranslation::find(salesTable.etg_DisplayDelieryCountryRegion(),'EN-US').ShortName;
        salesRegisterReportTmp.ShipToCountry        = LogisticsAddressCountryRegionTranslation::find(salesTable.etg_DisplayDelieryCountryRegion(),'EN-US').ShortName;

        select firstonly etg_orderType
            where etg_orderType.OrderType == salesTableTrade.OrderType;
        salesRegisterReportTmp.OrderTypeDescription = etg_orderType.Description;
        salesRegisterReportTmp.OrderType            = etg_orderType.OrderType;

        select firstonly salesAgreementHeader
            where salesAgreementHeader.RecId ==  salesTable.MatchingAgreement;

        select etg_salesagreementheader
            where etg_salesagreementheader.SalesAgreementId == salesAgreementHeader.SalesNumberSequence;

        select firstonly AgreementType
            where AgreementType.AgreementType == etg_salesagreementheader.AgreementType;
        salesRegisterReportTmp.AgreementType    =   AgreementType.AgreementType;
        salesRegisterReportTmp.Description      =   AgreementType.Description;

        salesAgreementHeader                        = SalesAgreementHeader::find(salesTable.MatchingAgreement);
        agreementHeader                             = AgreementHeader::find(salesTable.MatchingAgreement);
        salesRegisterReportTmp.SalesConractNumber   = salesAgreementHeader.SalesNumberSequence;
        salesRegisterReportTmp.SalesContractDate    = agreementHeader.DefaultAgreementLineEffectiveDate;

        select firstonly CommitedQuantity, ProductUnitOfMeasure, PricePerUnit from aLineCommitment order by RecId
            join agreementLine
            where agreementLine.RecId == aLineCommitment.RecId
            && agreementLine.Agreement == agreementHeader.RecId;

        salesRegisterReportTmp.SalesContractQty     = aLineCommitment.CommitedQuantity;
        salesRegisterReportTmp.SalesContractValue   = aLineCommitment.ProductUnitOfMeasure;
        salesRegisterReportTmp.SalesContractPrice   = aLineCommitment.PricePerUnit;

        if(salesTable.MatchingAgreement)
        {
            select firstonly purchAgreeementHeader
            join agreementReference
                where purchAgreeementHeader.RecId == agreementReference.SourceAgreement
                && agreementReference.DerivedAgreement == salesTable.MatchingAgreement;
        }

        if (!purchAgreeementHeader && salesAgreementHeader.SalesNumberSequence)
        {
            select firstonly purchAgreeementHeader
                where purchAgreeementHeader.ETG_SalesAgreementIdTP == salesAgreementHeader.SalesNumberSequence;

        }
        if (purchAgreeementHeader)
        {
            select firstonly CommitedQuantity, ProductUnitOfMeasure, PricePerUnit from aLineCommitment order by RecId
                join agreementLine
                where agreementLine.RecId == aLineCommitment.RecId
                && agreementLine.Agreement == purchAgreeementHeader.RecId;

            salesRegisterReportTmp.PurchContractNumber  = purchAgreeementHeader.PurchNumberSequence;
            salesRegisterReportTmp.PurchContractQty     = aLineCommitment.CommitedQuantity;
            salesRegisterReportTmp.PurchContractValue   = aLineCommitment.ProductUnitOfMeasure;
            salesRegisterReportTmp.PurchContractPrice   = aLineCommitment.PricePerUnit;
            salesRegisterReportTmp.PurchContractDate    = AgreementHeader::find(purchAgreeementHeader.RecId).DefaultAgreementLineEffectiveDate;

            agreementLineQuantityCommitment = agreementLine as AgreementLineQuantityCommitment;
            salesRegisterReportTmp.PurchContractLineAmount  = agreementLineQuantityCommitment.lineAmount();
        }

        custAccountTable                            = salesTable.custTable_CustAccount();
        salesRegisterReportTmp.CustAccount          = custAccountTable.AccountNum;
        salesRegisterReportTmp.CustName             = custAccountTable.name();
        salesRegisterReportTmp.BillToPartyAccount   = custAccountTable.AccountNum;
        salesRegisterReportTmp.BillToPartyName      = custAccountTable.name();
        salesRegisterReportTmp.BillToPartyCountry   = LogisticsAddressCountryRegionTranslation::find(custAccountTable.postalAddress().CountryRegionId,'EN-US').ShortName;

        select firstonly Name from fiscalCalendarYear
            where fiscalCalendarYear.StartDate <= salesRegisterReportTmp.CreatedDate
            && fiscalCalendarYear.EndDate >= salesRegisterReportTmp.CreatedDate;
        salesRegisterReportTmp.AccountingPeriod     = fiscalCalendarYear.Name;

        salesRegisterReportTmp.DeliveryOrderNum     = custPackingSlipJour.PackingSlipId;
        salesRegisterReportTmp.DeliveryOrderDate    = custPackingSlipJour.DeliveryDate;
        salesRegisterReportTmp.CustPackingSlipJour  = custPackingSlipJour.RecId;
        salesRegisterReportTmp.DeliveryQty          = custPackingSlipTrans.Qty;
        /*
        select firstonly inventTransOrigin
            where inventTransOrigin.InventTransId == salesLine.InventTransId;
        select firstonly inventTrans
            where inventTrans.InventTransOrigin == inventTransOrigin.RecId
            && inventTrans.Qty        == custPackingSlipJour.Qty;
        /*
        select firstonly custInvoiceTrans
            where custInvoiceTrans.InventTransId == inventTransorigin.InventTransId
            &&  custInvoiceTrans.Qty             == inventTrans.Qty;
        select firstonly custInvoiceJour
            where custInvoiceJour.SalesId        == salesLine.SalesId
            && custInvoiceJour.ledgerVoucher     == inventTrans.Voucher;
        */
        */
        salesRegisterReportTmp.InvoiceId            = custInvoiceJour.InvoiceId;
        salesRegisterReportTmp.InvoiceDate          = custInvoiceJour.InvoiceDate;
        salesRegisterReportTmp.BLnumber             = custPackingSlipJour.BOLNo;//   custInvoiceJour.ETG_BLnumber;

        if(salesRegisterReportTmp.BLnumber == "")
            salesRegisterReportTmp.BLnumber             = custInvoiceJour.ETG_BLnumber;

        salesRegisterReportTmp.InvoiceAmount        = custInvoiceJour.SalesBalance;
        salesRegisterReportTmp.InvoiceValue         = custInvoiceJour.InvoiceAmount;
        salesRegisterReportTmp.InvoiceRate          = custInvoiceTrans.SalesPrice;
        salesRegisterReportTmp.InvoiceQty           = custInvoiceTrans.Qty;

        select firstonly custTrans
            where custTrans.TransDate == custInvoiceJour.InvoiceDate
            && custTrans.AccountNum == custInvoiceJour.InvoiceAccount
            && custTrans.Voucher == custInvoiceJour.LedgerVoucher
            && custTrans.Invoice == custInvoiceJour.InvoiceId;

        salesRegisterReportTmp.AmountCur        = custTrans.AmountCur;
        salesRegisterReportTmp.ReportingCurrencyAmount  = custTrans.ReportingCurrencyAmount;
        salesRegisterReportTmp.InvCurrencyCode  = custTrans.CurrencyCode;
        salesRegisterReportTmp.AmountMST  = custTrans.AmountMST;

        select firstonly SourceRegulateAmountCur, TaxValue from taxTrans
            where taxTrans.SourceRecId == custInvoiceTrans.RecId
            && taxTrans.SourceTableId == tableNum(CustInvoiceTrans);
        salesRegisterReportTmp.TaxValue             = abs(taxTrans.TaxValue);

        select firstonly generalJournalAccountEntry
            where generalJournalAccountEntry.PostingType == LedgerPostingType::SalesConsump
        join generalJournalEntry
            where generalJournalEntry.RecId == generalJournalAccountEntry.GeneralJournalEntry
            && generalJournalEntry.SubledgerVoucher == custInvoiceJour.LedgerVoucher;
        salesRegisterReportTmp.ActualGIDate         = generalJournalEntry.AccountingDate;

        salesRegisterReportTmp.ItemId               = this.isGRNWithMulipleItems(salesRegisterReportTmp.SalesId, salesRegisterReportTmp.InventTransId) ? "Multiple" : custPackingSlipTrans.ItemId;

        select firstonly SourceRegulateAmountCur, TaxValue from taxTrans
        where taxTrans.SourceRecId == custInvoiceTrans.RecId
        && taxTrans.SourceTableId == tableNum(CustInvoiceTrans);
        salesRegisterReportTmp.TaxAmount            = abs(taxTrans.SourceRegulateAmountCur);

        select firstonly generalJournalAccountEntry
            where generalJournalAccountEntry.PostingType == LedgerPostingType::SalesOffsetAccountPackingSlip
        exists join generalJournalEntry
            where generalJournalEntry.RecId == generalJournalAccountEntry.GeneralJournalEntry
            && generalJournalEntry.SubledgerVoucher == custInvoiceJour.LedgerVoucher;
        salesRegisterReportTmp.COGSDiffered         = (-1*generalJournalAccountEntry.AccountingCurrencyAmount);

        select firstonly generalJournalAccountEntry
            where generalJournalAccountEntry.PostingType == LedgerPostingType::SalesConsump
        join generalJournalEntry
            where generalJournalEntry.RecId == generalJournalAccountEntry.GeneralJournalEntry
            && generalJournalEntry.SubledgerVoucher == custInvoiceJour.LedgerVoucher;
        salesRegisterReportTmp.COGSActual           = generalJournalAccountEntry.AccountingCurrencyAmount;

        select firstonly generalJournalAccountEntry
        where generalJournalAccountEntry.PostingType == LedgerPostingType::SalesConsump
            join generalJournalEntry
        where generalJournalEntry.RecId == generalJournalAccountEntry.GeneralJournalEntry
        && generalJournalEntry.SubledgerVoucher == custInvoiceJour.LedgerVoucher;
        salesRegisterReportTmp.ActualGIDate         = generalJournalEntry.AccountingDate;

        salesRegisterReportTmp.ItemName             = salesLine.itemName();
        salesRegisterReportTmp.ItemId               = salesLine.ItemId;
        salesRegisterReportTmp.SalesUnit            = salesLine.SalesUnit;
        salesRegisterReportTmp.SKU                  = InventTableModule::find(salesLine.ItemId, ModuleInventPurchSales::Invent).UnitId;
        salesRegisterReportTmp.SalesQty             = salesLine.SalesQty;
        //salesRegisterReportTmp.GrossContribution    = salesLine.LineAmount - salesRegisterReportTmp.COGSActual;
        salesRegisterReportTmp.GrossContribution    = salesLine.LineAmount - salesRegisterReportTmp.COGSDiffered;

        // start  sales register s3 date 28/03/2022

        salesRegisterReportTmp.GCBeforeRecal        = (salesRegisterReportTmp.InvoiceAmount - salesRegisterReportTmp.COGSDiffered);
        /*
        select  firstonly  inventTransOriginAdj
           where inventTransOriginAdj.ReferenceCategory == InventTransType::Sales
        join inventTransAdj
            where inventTransAdj.InventTransOrigin == InventTransOrigin::findByInventTransId(salesLine.InventTransId).RecId;
            */
       // select sum(CostAmountPosted),   Sum(CostAmountAdjustment) from  inventTransAdj
            amount ActualValue = 0;
           // InvoiceId Value=inventTransAdj.InvoiceId;
            while  select  *from inventTransAdj 
            join inventTransOriginAdj
            where inventTransAdj.InventTransOrigin ==  inventTransOriginAdj.RecId &&//InventTransOrigin::findByInventTransId(salesLine.InventTransId).RecId &&
            inventTransOriginAdj.InventTransId ==  salesLine.InventTransId &&
            inventTransOriginAdj.ReferenceCategory == InventTransType::Sales
        {
            //while(inventTransAdj.StatusIssue == StatusIssue::Sold && inventTransAdj.InvoiceId ==Value)
            {
            ActualValue =(ActualValue + (-1* inventTransAdj.costValue()));
           // Value = inventTransAdj.InvoiceId
            }

        }
        salesRegisterReportTmp.COGSActual           = ActualValue;//((-1*inventTransAdj.CostAmountPosted) + (-1* inventTransAdj.CostAmountAdjustment) );
        salesRegisterReportTmp.GCAfterFIFO          = (salesRegisterReportTmp.InvoiceAmount - salesRegisterReportTmp.COGSActual);

        //End sales register s3 date 28/03/2022

        while select ReferenceId from inventTransOriginMarked
            where inventTransOriginMarked.ReferenceCategory == InventTransType::Purch
        join inventTransMarking
            where inventTransMarking.InventTransOrigin == InventTransOrigin::findByInventTransId(salesLine.InventTransId).RecId
            && inventTransMarking.MarkingRefInventTransOrigin == inventTransOriginMarked.RecId
        {
            if(!strScan(markedPurchIds, inventTransOriginMarked.ReferenceId, 1, strLen(markedPurchIds)))
            {
                markedPurchIds += strFmt("%1, ", inventTransOriginMarked.ReferenceId);
            }
        }
        if(strScan(markedPurchIds, ",", 1, strLen(markedPurchIds)))
        {
            markedPurchIds                          = subStr(markedPurchIds, 1, strLen(markedPurchIds)-2);
        }

        salesRegisterReportTmp.PurchId              = markedPurchIds;

        //select firstonly MarkingRefInventTransOrigin from inventTransMarking
        //    where inventTransMarking.InventTransOrigin == InventTransOrigin::findByInventTransId(salesLine.InventTransId).RecId
        //    && inventTransMarking.MarkingRefInventTransOrigin;

        //select firstonly ReferenceId from inventTransOriginMarked
        //    where inventTransOriginMarked.ReferenceCategory == InventTransType::Purch
        //    && inventTransOriginMarked.RecId == inventTransMarking.MarkingRefInventTransOrigin;
        //salesRegisterReportTmp.PurchId              = inventTransOriginMarked.ReferenceId;

        salesRegisterReportTmp.SalesQtyInTon        = this.getNormalConversion(salesLine.ItemId, salesLine.SalesQty, salesLine.SalesUnit, "t");
        if(salesRegisterReportTmp.SalesQtyInTon == 0 && salesLine.ItemId && salesLine.SalesQty && salesLine.SalesUnit)
        {
            salesRegisterReportTmp.SalesQtyInTon        = this.getStandardConversion(salesLine.ItemId, salesLine.SalesQty, salesLine.SalesUnit, "MT");
        }
        salesRegisterReportTmp.SalesQtyInTon        = salesRegisterReportTmp.SalesQtyInTon != 0 ? salesRegisterReportTmp.SalesQtyInTon : salesRegisterReportTmp.SalesQty;
        salesRegisterReportTmp.LineDisc             = salesLine.LineDisc;
        salesRegisterReportTmp.LineAmount           = salesLine.LineAmount;
        salesRegisterReportTmp.LinePercent          = salesLine.LinePercent;
        salesRegisterReportTmp.InventColorId        = inventDim.InventColorId;
        salesRegisterReportTmp.inventBatchId        = inventDim.inventBatchId;
        if (!salesRegisterReportTmp.inventBatchId)
        {
            salesRegisterReportTmp.inventBatchId    = InventTrans::findTransId(custPackingSlipTrans.InventTransId).inventDim().inventBatchId;
        }
        salesRegisterReportTmp.InventStyleId        = inventDim.InventStyleId;
        salesRegisterReportTmp.configId             = inventDim.configId;
        salesRegisterReportTmp.InventSizeId         = inventDim.InventSizeId;
        salesRegisterReportTmp.InventSiteId         = inventDim.InventSiteId;
        salesRegisterReportTmp.InventSiteName       = InventSite::find(inventDim.InventSiteId).Name;
        salesRegisterReportTmp.InventLocationId     = inventDim.InventLocationId;
        salesRegisterReportTmp.InventLocationName   = InventLocation::find(salesRegisterReportTmp.InventLocationId).Name;
        salesRegisterReportTmp.wMSLocationId        = inventDim.wMSLocationId;
        if (!salesRegisterReportTmp.wMSLocationId)
        {
            salesRegisterReportTmp.wMSLocationId    = InventTrans::findTransId(custPackingSlipTrans.InventTransId).inventDim().wMSLocationId;
        }
        salesRegisterReportTmp.LicensePlateId       = inventDim.LicensePlateId;
        salesRegisterReportTmp.InventStatusId       = inventDim.InventStatusId;
        salesRegisterReportTmp.inventSerialId       = inventDim.inventSerialId;
        salesRegisterReportTmp.InventOwnerId_RU     = inventDim.InventOwnerId_RU;
        // 17022021 start
        salesRegisterReportTmp.CompanyLogo          = FormLetter::companyLogo();
        // 17022021 end
        salesRegisterReportTmp.insert();
    }
}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
{
    DimensionAttributeValueSetStorage   dimStorage;
    DimensionAttribute                  dimAttribute;
    DimensionValue                      displayValue = "";
    Description                         dimDescription = "";
    int                                 i;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
    for (i= 1 ; i<= dimStorage.elements() ; i++)
    {
        dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

        if(dimAttribute.Name == _dimensionName)
        {
            displayValue    = dimStorage.getDisplayValueByIndex(i);
            dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
            if (dimDescription == "")
            {
                dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
            }
        }
    }

    return  dimDescription;
}

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
{
    DimAttributeInventTable         inventTable;
    DimAttributeHcmWorker           worker;
    DimAttributeCustTable           custTable;
    DimAttributeVendTable           dimVendTable;
    DimAttributeAssetTable          assetTable;
    DimAttributeOMBusinessUnit      businessUnit;
    DimAttributeOMCostCenter        costCenter;
    DimAttributeOMDepartment        department;
    Description                     dimDescription = "";

    switch (_ViewName)
    {
        case  "DimAttributeInventTable":
            select Name from inventTable
                where inventTable.value == _displayValue;
            dimDescription = inventTable.Name;
            break;
        case  "DimAttributeHcmWorker":
            select Name from worker
                where worker.value == _displayValue;
            dimDescription = worker.Name;
            break;
        case  "DimAttributeCustTable":
            select Name from custTable
                where custTable.value == _displayValue;
            dimDescription = custTable.Name;
            break;
        case  "DimAttributeVendTable":
            select Name from dimVendTable
                where dimVendTable.value == _displayValue;
            dimDescription = dimVendTable.Name;
            break;
        case  "DimAttributeAssetTable":
            select Name from assetTable
                where assetTable.value == _displayValue;
            dimDescription = assetTable.Name;
            break;
        case  "DimAttributeOMBusinessUnit":
            select Name from businessUnit
                where businessUnit.value == _displayValue;
            dimDescription = businessUnit.Name;
            break;
        case  "DimAttributeOMCostCenter":
            select Name from costCenter
                where costCenter.value == _displayValue;
            dimDescription = costCenter.Name;
            break;
        case  "DimAttributeOMDepartment":
            select Name from department
                where department.value == _displayValue;
            dimDescription = department.Name;
            break;
    }

    return      dimDescription;
}

private SalesOrderedQty getNormalConversion(ItemId  _ItemId, Qty    _Qty, UnitOfMeasureSymbol _FromUOM, UnitOfMeasureSymbol _ToUOM)
{
    InventTable             inventTable;
    UnitOfMeasureConversion unitOfMeasureConversion;
    UnitOfMeasure           fromUnitOfMeasure, toUnitOfMeasure;
    SalesOrderedQty         returnValue;

    select firstonly Factor from unitOfMeasureConversion
    exists join InventTable
        where inventTable.ItemId == _ItemId
        && unitOfMeasureConversion.Product == InventTable.Product
    exists join fromUnitOfMeasure // FromUnit
        where fromUnitOfMeasure.RecId == unitOfMeasureConversion.FromUnitOfMeasure
        && fromUnitOfMeasure.Symbol == _FromUOM
    exists join toUnitOfMeasure //ToUnit
        where toUnitOfMeasure.RecId == unitOfMeasureConversion.TOUNITOFMEASURE
        && toUnitOfMeasure.Symbol == _ToUOM;

    returnValue = unitOfMeasureConversion.Factor != 0 ? roundup(_Qty/unitOfMeasureConversion.Factor, 1) : 0;

    return returnValue;
}

private SalesOrderedQty getStandardConversion(ItemId  _ItemId, Qty    _Qty, UnitOfMeasureSymbol _FromUOM, UnitOfMeasureSymbol _ToUOM)
{
    InventTable                     inventTable;
    UnitOfMeasureConversion         unitOfMeasureConversion;
    UnitOfMeasure                   fromUnitOfMeasure, toUnitOfMeasure;
    SalesOrderedQty                 returnValue;
    UnitOfMeasureConverter_Product  unitConverter  = UnitOfMeasureConverter_Product::construct();

    select firstonly Factor from unitOfMeasureConversion
    exists join InventTable
        where inventTable.ItemId == _ItemId
        && unitOfMeasureConversion.Product == InventTable.Product
    exists join fromUnitOfMeasure // FromUnit
    where fromUnitOfMeasure.RecId == unitOfMeasureConversion.FromUnitOfMeasure
        && fromUnitOfMeasure.Symbol == _FromUOM
    exists join toUnitOfMeasure //ToUnit
    where toUnitOfMeasure.RecId == unitOfMeasureConversion.TOUNITOFMEASURE
        && toUnitOfMeasure.Symbol == _ToUOM;
    unitConverter.parmProduct(InventTable::find(_ItemId,true).Product);
    unitConverter.parmFromUnitOfMeasure(UnitOfMeasure::unitOfMeasureIdBySymbol(_FromUOM));
    unitConverter.parmToUnitOfMeasure(UnitOfMeasure::unitOfMeasureIdBySymbol(_ToUOM));
    unitConverter.parmRoundAbsoluteValue(NoYes::Yes);
    unitConverter.parmApplyRounding(NoYes::Yes);

    if (unitOfMeasureConversion)
    {
        returnValue = unitConverter.convertValue(_Qty);
    }

    return returnValue;
}

/// <summary>
///    checking whether the dimenstion is include in the select Set
/// </summary>
/// <param name = "_setName">set name</param>
/// <param name = "_dimensionName">dimension name</param>
/// <returns>
///    The <c>Boolean</c>
/// </returns>
public boolean isDimensionIncludedInSet(Name        _setName, Name     _dimensionName)
{
    FinancialDimensionSetEntity     financialDimensionSetEntity;

    select firstonly financialDimensionSetEntity
        where financialDimensionSetEntity.Name == _setName
        && (financialDimensionSetEntity.SegmentName01 == _dimensionName ||
        financialDimensionSetEntity.SegmentName02 == _dimensionName ||
        financialDimensionSetEntity.SegmentName03 == _dimensionName ||
        financialDimensionSetEntity.SegmentName04 == _dimensionName ||
        financialDimensionSetEntity.SegmentName05 == _dimensionName ||
        financialDimensionSetEntity.SegmentName06 == _dimensionName ||
        financialDimensionSetEntity.SegmentName07 == _dimensionName ||
        financialDimensionSetEntity.SegmentName08 == _dimensionName ||
        financialDimensionSetEntity.SegmentName09 == _dimensionName ||
        financialDimensionSetEntity.SegmentName10 == _dimensionName ||
        financialDimensionSetEntity.SegmentName11 == _dimensionName
        );

    return financialDimensionSetEntity.RecId;
}

/// <summary>
///    updating data useing for inserted columns
/// </summary>
public void updateData()
{
    SalesId         curSalesId;
    RefRecId        curSalesLine;
    PackingSlipId   curPackingSlipId;
    InvoiceId       curInvoiceId;


    if (!isDetailReport)
    {
        ttsbegin;
        while select forupdate salesRegisterReportTmp
            order by InvoiceId
            where salesRegisterReportTmp.InvoiceId
        {
            if (curInvoiceId != salesRegisterReportTmp.InvoiceId)
            {
                curInvoiceId        = salesRegisterReportTmp.InvoiceId;
            }
            else
            {
                salesRegisterReportTmp.InvoiceAmount    = 0;
                salesRegisterReportTmp.InvoiceQty       = 0;
                salesRegisterReportTmp.InvoiceRate      = 0;
                salesRegisterReportTmp.InvoiceValue     = 0;
                salesRegisterReportTmp.AmountCur        = 0;
                salesRegisterReportTmp.ReportingCurrencyAmount  = 0;
                salesRegisterReportTmp.AmountMST        = 0;
                salesRegisterReportTmp.TaxAmount        = 0;
                salesRegisterReportTmp.COGSDiffered     = 0;
                salesRegisterReportTmp.COGSActual       = 0;
                salesRegisterReportTmp.GrossContribution= 0;
                salesRegisterReportTmp.update();
            }
        }

        while select forupdate salesRegisterReportTmp
            order by SalesLine
            where salesRegisterReportTmp.SalesLine
        {
            if (curSalesLine != salesRegisterReportTmp.SalesLine)
            {
                curSalesLine        = salesRegisterReportTmp.SalesLine;
            }
            else
            {
                salesRegisterReportTmp.SalesQty         = 0;
                salesRegisterReportTmp.SalesQtyInTon    = 0;
                salesRegisterReportTmp.LineAmount       = 0;
                salesRegisterReportTmp.LinePercent      = 0;
                salesRegisterReportTmp.LineDisc         = 0;
                salesRegisterReportTmp.update();
            }
        }

        while select forupdate salesRegisterReportTmp
            order by DeliveryOrderNum
            where salesRegisterReportTmp.DeliveryOrderNum
        {
            if (curPackingSlipId != salesRegisterReportTmp.DeliveryOrderNum)
            {
                curPackingSlipId    = salesRegisterReportTmp.DeliveryOrderNum;
            }
            else
            {
                salesRegisterReportTmp.DeliveryQty      = 0;
                salesRegisterReportTmp.update();
            }
        }
        ttscommit;
    }
}

