/// <summary>
///    inserting charges codes of a Agreement for specified invoiceid
/// </summary>
public void insertChargeCodes()
{
    RecordInsertList            chargeCodesList;
    ETG_ActualAgreementNew      actualAgreementNew;
    ETG_Chargecodelines         chargecodelines;
    ETG_ChargeCodes             chargeCodes;

    if (!isDetailReport)
    {
        while select maxof(SalesId), maxof(DeliveryOrderNum) from salesRegisterReportTmp
            group by SalesLine, SalesConractNumber, InvoiceId
            where salesRegisterReportTmp.SalesLine
            && salesRegisterReportTmp.SalesConractNumber
            && salesRegisterReportTmp.InvoiceId
            && salesRegisterReportTmp.IsActualOrderLine == NoYes::Yes
        {
            ssrsReportMultiParametersTmp.clear();
            ssrsReportMultiParametersTmp.ElementRecId1  = salesRegisterReportTmp.SalesLine;
            ssrsReportMultiParametersTmp.ElementStr1    = salesRegisterReportTmp.SalesConractNumber;
            ssrsReportMultiParametersTmp.ElementStr2    = salesRegisterReportTmp.InvoiceId;
            ssrsReportMultiParametersTmp.ElementStr3    = salesRegisterReportTmp.SalesId;
            ssrsReportMultiParametersTmp.ElementStr4    = salesRegisterReportTmp.DeliveryOrderNum;
            ssrsReportMultiParametersTmp.insert();
            currentTransactionIdChrg                    = ssrsReportMultiParametersTmp.CreatedTransactionId;
        }
    }
    else
    {
        while select maxof(SalesId), maxof(DeliveryOrderNum) from salesRegisterReportTmp
            group by ActualSalesLine, SalesConractNumber, InvoiceId
            where salesRegisterReportTmp.ActualSalesLine
            && salesRegisterReportTmp.SalesConractNumber
            && salesRegisterReportTmp.InvoiceId
            && salesRegisterReportTmp.IsActualOrderLine == NoYes::No
        {
            ssrsReportMultiParametersTmp.clear();
            ssrsReportMultiParametersTmp.ElementRecId1  = salesRegisterReportTmp.ActualSalesLine;
            ssrsReportMultiParametersTmp.ElementStr1    = salesRegisterReportTmp.SalesConractNumber;
            ssrsReportMultiParametersTmp.ElementStr2    = salesRegisterReportTmp.InvoiceId;
            ssrsReportMultiParametersTmp.ElementStr3    = salesRegisterReportTmp.SalesId;
            ssrsReportMultiParametersTmp.ElementStr4    = salesRegisterReportTmp.DeliveryOrderNum;
            ssrsReportMultiParametersTmp.insert();
            currentTransactionIdChrg                    = ssrsReportMultiParametersTmp.CreatedTransactionId;
        }
    }

    while select ssrsReportMultiParametersTmp
        where ssrsReportMultiParametersTmp.CreatedTransactionId == currentTransactionIdChrg
    {
        while select chargecodelines
            where chargecodelines.InvoiceId == ssrsReportMultiParametersTmp.ElementStr2
        exists join chargeCodes
            where chargeCodes.ETG_Estimation == chargecodelines.ETG_Estimation
            && chargeCodes.PurchNumberSequence == chargecodelines.PurchNumberSequence
            && chargeCodes.PurchNumberSequence == ssrsReportMultiParametersTmp.ElementStr1
        {
            salesRegisterReportTmp.clear();
            salesRegisterReportTmp.SalesLine            = ssrsReportMultiParametersTmp.ElementRecId1;
            salesRegisterReportTmp.SalesConractNumber   = ssrsReportMultiParametersTmp.ElementStr1;
            salesRegisterReportTmp.InvoiceId            = ssrsReportMultiParametersTmp.ElementStr2;
            salesRegisterReportTmp.SalesId              = ssrsReportMultiParametersTmp.ElementStr3;
            salesRegisterReportTmp.DeliveryOrderNum     = ssrsReportMultiParametersTmp.ElementStr4;
            salesRegisterReportTmp.ChargeCode           = chargecodelines.MarkupCode;
            //salesRegisterReportTmp.EstimatedValue       = chargecodelines.Value;
            salesRegisterReportTmp.EstimatedValue       = chargecodelines.AmountMST;
            salesRegisterReportTmp.insert();
        }

        while select actualAgreementNew
            where actualAgreementNew.InvoiceId == ssrsReportMultiParametersTmp.ElementStr2
        join chargecodelines
            where chargecodelines.PurchId == actualAgreementNew.PurchId
            && chargecodelines.InvoiceId == ssrsReportMultiParametersTmp.ElementStr2
        exists join chargeCodes
            where chargeCodes.ETG_Estimation == chargecodelines.ETG_Estimation
            && chargeCodes.PurchNumberSequence == chargecodelines.PurchNumberSequence
            && actualAgreementNew.ETG_Estimation == chargeCodes.ETG_Estimation
            && actualAgreementNew.PurchNumberSequence == chargeCodes.PurchNumberSequence
            && chargeCodes.PurchNumberSequence == ssrsReportMultiParametersTmp.ElementStr1
        {
            salesRegisterReportTmp.clear();
            salesRegisterReportTmp.SalesLine            = ssrsReportMultiParametersTmp.ElementRecId1;
            salesRegisterReportTmp.SalesConractNumber   = ssrsReportMultiParametersTmp.ElementStr1;
            salesRegisterReportTmp.InvoiceId            = ssrsReportMultiParametersTmp.ElementStr2;
            salesRegisterReportTmp.SalesId              = ssrsReportMultiParametersTmp.ElementStr3;
            salesRegisterReportTmp.DeliveryOrderNum     = ssrsReportMultiParametersTmp.ElementStr4;
            salesRegisterReportTmp.ChargeCode           = chargecodelines.MarkupCode;
            //salesRegisterReportTmp.ActualValue          = actualAgreementNew.Value;
            salesRegisterReportTmp.ActualValue          = actualAgreementNew.AmountMST;
            salesRegisterReportTmp.insert();
        }
    }

    delete_from ssrsReportMultiParametersTmp
        where ssrsReportMultiParametersTmp.CreatedTransactionId == currentTransactionIdChrg;
}

public  boolean isGRNWithMulipleInvoices(SalesId    _SalesId, InventTransId _GRNInventTransId)
{
    boolean             mulipleInvoices = false;
    CustInvoiceJour     custInvoiceJour;
    CustInvoiceTrans    custInvoiceTrans;

    select count(RecId) from custInvoiceJour
    exists join custInvoiceTrans
        where custInvoiceTrans.SalesId == custInvoiceJour.SalesId
        && custInvoiceTrans.InvoiceId == custInvoiceJour.InvoiceId
        && custInvoiceTrans.InvoiceDate == custInvoiceJour.InvoiceDate
        && custInvoiceTrans.numberSequenceGroup == custInvoiceJour.numberSequenceGroup
        && custInvoiceTrans.SalesId == _SalesId
        && custInvoiceTrans.InventTransId == _GRNInventTransId;

    mulipleInvoices = custInvoiceJour.RecId > 1 ? true : false;

    return  mulipleInvoices;
}

public  boolean isGRNWithMulipleItems(SalesId   _SalesId, InventTransId _GRNInventTransId)
{
    boolean                 mulipleInvoices = false;
    CustPackingSlipJour     custPackingSlipJourLoc;
    CustPackingSlipTrans    custPackingSlipTransLoc;

    select count(RecId) from custPackingSlipTransLoc
    exists join custPackingSlipJourLoc
        where custPackingSlipTransLoc.SalesId == custPackingSlipJourLoc.SalesId
        && custPackingSlipTransLoc.DeliveryDate == custPackingSlipJourLoc.DeliveryDate
        && custPackingSlipTransLoc.PackingSlipId == custPackingSlipJourLoc.PackingSlipId
        && custPackingSlipTransLoc.SalesId == _SalesId
        && custPackingSlipTransLoc.InventTransId == _GRNInventTransId;

    mulipleInvoices = custPackingSlipTransLoc.RecId > 1 ? true : false;

    return  mulipleInvoices;
}
